import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';

function Home() {
  // Array of images for the carousel
  const carouselImages = [
    {
      url: "https://images.unsplash.com/photo-1522202176988-66273c2fd55f?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1471&q=80",
      alt: "Students collaborating on projects"
    },
    {
      url: "https://images.unsplash.com/photo-1523240795612-9a054b0db644?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1470&q=80",
      alt: "Students working together in library"
    },
    {
      url: "https://images.unsplash.com/photo-1531482615713-2afd69097998?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1470&q=80",
      alt: "Students discussing project"
    },
    {
      url: "https://images.unsplash.com/photo-1517245386807-bb43f82c33c4?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1470&q=80",
      alt: "Students using laptops"
    }
  ];

  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  const [showRegisterModal, setShowRegisterModal] = useState(false);
  
  // Registration form state from your Registration component
  const [formData, setFormData] = useState({
    fullName: '',
    email: '',
    serviceType: 'Web Development',
    projectDetails: '',
    paymentMethod: 'Cash'
  });

  const [message, setMessage] = useState('');

  // Auto slide effect
  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentImageIndex((prevIndex) => 
        prevIndex === carouselImages.length - 1 ? 0 : prevIndex + 1
      );
    }, 3000);

    return () => clearInterval(interval);
  }, []);

  // Handle form input changes
  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  // Handle form submission
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (formData.paymentMethod === 'Online') {
        alert("Redirecting to Secure Online Payment Gateway...");
      }

      const response = await axios.post('http://localhost:5000/api/hire', formData);
      
      if (response.status === 201) {
        setMessage("✅ Success! Your request and payment preference have been saved.");
        setTimeout(() => {
          setMessage('');
          setShowRegisterModal(false);
        }, 2000);
        
        setFormData({ 
          fullName: '', 
          email: '', 
          serviceType: 'Web Development', 
          projectDetails: '', 
          paymentMethod: 'Cash' 
        });
      }
    } catch (error) {
      console.error("Error saving data:", error);
      setMessage("❌ Error! Could not connect to the server.");
    }
  };

  // Close modal when clicking outside
  const handleOverlayClick = (e) => {
    if (e.target.classList.contains('modal-overlay')) {
      setShowRegisterModal(false);
      setMessage('');
    }
  };

  return (
    <div className="home-page">
      {/* 1. Hero Section - Student Freelancer Theme Image with Carousel */}
      <header className="py-5 text-white" style={{ background: 'linear-gradient(135deg, #1e3c72 0%, #2a5298 100%)', minHeight: '85vh', display: 'flex', alignItems: 'center' }}>
        <div className="container py-5 text-center text-lg-start">
          <div className="row align-items-center">
            
            {/* डावी बाजू: मजकूर */}
            <div className="col-lg-6 mb-5 mb-lg-0">
              <h1 className="display-4 fw-bold mb-3 animate__animated animate__fadeInLeft">
                <span className="text-warning">Student Freelancer</span> Marketplace
              </h1>
              <p className="lead fs-4 mb-4 opacity-75">
                Connect with talented students from Nashik for web development, design, and technical solutions at affordable prices.
              </p>
              <div className="d-grid gap-3 d-sm-flex justify-content-lg-start justify-content-center">
                <Link to="/services" className="btn btn-warning btn-lg px-5 fw-bold shadow">Find Freelancers</Link>
                <button onClick={() => setShowRegisterModal(true)} className="btn btn-outline-light btn-lg px-5 fw-bold">Hire a Freelancer</button>
              </div>
            </div>

            {/* उजवी बाजू: Auto-moving Image Carousel */}
            <div className="col-lg-6 text-center">
              <div className="image-wrapper shadow-lg rounded-4 p-2 bg-white-50 position-relative">
                <img 
                  src={carouselImages[currentImageIndex].url}
                  alt={carouselImages[currentImageIndex].alt}
                  className="img-fluid rounded-4 shadow border border-5 border-white"
                  style={{ width: '100%', height: 'auto', display: 'block', minHeight: '350px', objectFit: 'cover' }}
                />
                
                {/* Carousel Indicators */}
                <div className="position-absolute bottom-0 start-50 translate-middle-x mb-3 d-flex gap-2">
                  {carouselImages.map((_, index) => (
                    <button
                      key={index}
                      onClick={() => setCurrentImageIndex(index)}
                      className={`rounded-circle p-0 border-0 ${index === currentImageIndex ? 'bg-warning' : 'bg-white'}`}
                      style={{ width: '12px', height: '12px', opacity: index === currentImageIndex ? 1 : 0.5 }}
                      aria-label={`Go to slide ${index + 1}`}
                    />
                  ))}
                </div>
              </div>
            </div>

          </div>
        </div>
      </header>

      {/* 2. Features Section (Clickable Cards) */}
      <section className="py-5 bg-light border-bottom border-top">
        <div className="container py-5 text-center">
          <h2 className="fw-bold mb-5 display-5">Why Choose Student Freelancers?</h2>
          <div className="row g-4">
            <div className="col-md-4">
              <Link to="/services" className="text-decoration-none">
                <div className="card h-100 border-0 shadow-sm p-4 feature-card">
                  <div className="display-5 text-primary mb-3">💰</div>
                  <h4 className="fw-bold text-dark">Affordable Rates</h4>
                  <p className="text-muted small">Get quality work at student-friendly prices, perfect for startups and small businesses.</p>
                </div>
              </Link>
            </div>
            <div className="col-md-4">
              <Link to="/services" className="text-decoration-none">
                <div className="card h-100 border-0 shadow-sm p-4 feature-card">
                  <div className="display-5 text-danger mb-3">🎓</div>
                  <h4 className="fw-bold text-dark">Fresh Talent</h4>
                  <p className="text-muted small">Work with motivated students learning the latest technologies and trends.</p>
                </div>
              </Link>
            </div>
            <div className="col-md-4">
              <Link to="/services" className="text-decoration-none">
                <div className="card h-100 border-0 shadow-sm p-4 feature-card">
                  <div className="display-5 text-success mb-3">🤝</div>
                  <h4 className="fw-bold text-dark">Local Connection</h4>
                  <p className="text-muted small">Connect with talented students right here in Nashik for better collaboration.</p>
                </div>
              </Link>
            </div>
          </div>
        </div>
      </section>

      {/* 3. Testimonials Section - Student Focused */}
      <section className="py-5 bg-white">
        <div className="container py-5">
          <h2 className="text-center fw-bold mb-5 display-5 text-dark">Success Stories from Nashik</h2>
          <div className="row g-4 text-center">
            <div className="col-md-4">
              <div className="p-4 border rounded-4 shadow-sm italic bg-light h-100 shadow-hover">
                <p className="text-muted fs-5">"As a CS student, I earned my first ₹15,000 through this platform!"</p>
                <h6 className="fw-bold mb-0 text-primary">- Aditya Deshmukh, COEP</h6>
              </div>
            </div>
            <div className="col-md-4">
              <div className="p-4 border rounded-4 shadow-sm italic bg-light h-100 shadow-hover">
                <p className="text-muted fs-5">"Found a brilliant student developer for my startup website."</p>
                <h6 className="fw-bold mb-0 text-primary">- Priya Jadhav, Local Business Owner</h6>
              </div>
            </div>
            <div className="col-md-4">
              <div className="p-4 border rounded-4 shadow-sm italic bg-light h-100 shadow-hover">
                <p className="text-muted fs-5">"Best platform for students to showcase their skills in Nashik!"</p>
                <h6 className="fw-bold mb-0 text-primary">- Raj Patil, KK Wagh Institute</h6>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* 4. Contact Us & Map Section - Nashik Location */}
      <section id="contact" className="py-5 bg-light border-top border-bottom">
        <div className="container py-5">
          <h2 className="text-center fw-bold mb-5 display-5 text-dark">Visit Our Nashik Hub</h2>
          <div className="row g-5 align-items-center">
            <div className="col-lg-6">
              <div className="shadow-lg rounded-4 overflow-hidden border border-4 border-white" style={{ height: '400px' }}>
                <iframe 
                  title="Nashik Student Hub Location"
                  src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d119975.6327126835!2d73.73403917409225!3d19.991707350000004!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x3bddebef8fdfd52f%3A0xcdd25dc0334a738b!2sNashik%2C%20Maharashtra!5e0!3m2!1sen!2sin!4v1700000000000!5m2!1sen!2sin" 
                  width="100%" 
                  height="100%" 
                  style={{ border: 0 }} 
                  allowFullScreen="" 
                  loading="lazy"
                  referrerPolicy="no-referrer-when-downgrade">
                </iframe>
              </div>
            </div>
            <div className="col-lg-6">
              <div className="ps-lg-4 text-center text-lg-start">
                <h3 className="fw-bold mb-4 text-primary">Nashik Student Freelancer Hub</h3>
                <div className="mb-4 text-dark fs-5 shadow-sm p-4 bg-white rounded-4 border">
                  <p className="mb-3 d-flex align-items-center justify-content-center justify-content-lg-start">
                    <i className="fas fa-envelope text-primary me-3"></i> 
                    <strong>Email:</strong> students@nashikfreelance.in
                  </p>
                  <p className="mb-3 d-flex align-items-center justify-content-center justify-content-lg-start">
                    <i className="fas fa-phone text-success me-3"></i> 
                    <strong>Call:</strong> +91 98765 43210
                  </p>
                  <p className="mb-3 d-flex align-items-center justify-content-center justify-content-lg-start">
                    <i className="fas fa-map-marker-alt text-danger me-3"></i> 
                    <strong>Main Hub:</strong> College Road, Nashik, Maharashtra 422005
                  </p>
                  <p className="mb-0 d-flex align-items-center justify-content-center justify-content-lg-start">
                    <i className="fas fa-clock text-warning me-3"></i> 
                    <strong>Hours:</strong> Mon-Sat, 10 AM - 7 PM
                  </p>
                </div>
                <button onClick={() => setShowRegisterModal(true)} className="btn btn-primary btn-lg w-100 fw-bold shadow-sm">
                   Hire a Student Freelancer
                </button>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* 5. Footer Style CTA - Student Focused */}
      <footer className="py-5 text-center container my-5 bg-dark text-white rounded-5 p-5 shadow-lg">
        <h2 className="fw-bold mb-3">Ready to start your project?</h2>
        <p className="lead mb-4 opacity-75">Join Nashik's growing community of student freelancers and find the perfect match for your project.</p>
        <div className="d-flex justify-content-center gap-3">
          <button onClick={() => setShowRegisterModal(true)} className="btn btn-primary btn-lg px-5 fw-bold shadow">Hire a Freelancer</button>
          <Link to="/services" className="btn btn-outline-light btn-lg px-5 fw-bold">Explore Services</Link>
        </div>
        <p className="mt-4 text-white-50 small">📍 Based in Nashik, Maharashtra - Serving clients worldwide</p>
      </footer>

      {/* Registration Modal/Popup - Using your Registration component form */}
      {showRegisterModal && (
        <div className="modal-overlay" onClick={handleOverlayClick} style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: 'rgba(0, 0, 0, 0.7)',
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          zIndex: 1000,
          padding: '20px'
        }}>
          <div className="modal-content" style={{
            backgroundColor: 'white',
            borderRadius: '15px',
            maxWidth: '500px',
            width: '100%',
            maxHeight: '90vh',
            overflowY: 'auto',
            position: 'relative',
            animation: 'slideIn 0.3s ease-out'
          }}>
            {/* Modal Header */}
            <div style={{
              padding: '20px',
              borderBottom: '1px solid #dee2e6',
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'center',
              background: 'linear-gradient(135deg, #1e3c72 0%, #2a5298 100%)',
              color: 'white',
              borderRadius: '15px 15px 0 0'
            }}>
              <h3 className="fw-bold mb-0">Hire a Student Freelancer</h3>
              <button 
                onClick={() => {
                  setShowRegisterModal(false);
                  setMessage('');
                }}
                style={{
                  background: 'none',
                  border: 'none',
                  color: 'white',
                  fontSize: '24px',
                  cursor: 'pointer'
                }}
              >
                &times;
              </button>
            </div>

            {/* Modal Body - Registration Form from your Registration component */}
            <div style={{ padding: '20px' }}>
              {message && (
                <div className={`alert ${message.includes('Success') ? 'alert-success' : 'alert-danger'} text-center`}>
                  {message}
                </div>
              )}

              <form onSubmit={handleSubmit}>
                {/* Full Name */}
                <div className="mb-3">
                  <label className="form-label fw-bold">Full Name</label>
                  <input 
                    type="text" 
                    name="fullName" 
                    className="form-control" 
                    value={formData.fullName} 
                    onChange={handleChange} 
                    required 
                    style={{ padding: '10px', borderRadius: '8px' }}
                  />
                </div>

                {/* Email */}
                <div className="mb-3">
                  <label className="form-label fw-bold">Email Address</label>
                  <input 
                    type="email" 
                    name="email" 
                    className="form-control" 
                    value={formData.email} 
                    onChange={handleChange} 
                    required 
                    style={{ padding: '10px', borderRadius: '8px' }}
                  />
                </div>

                {/* Service Type */}
                <div className="mb-3">
                  <label className="form-label fw-bold">Select Service</label>
                  <select 
                    name="serviceType" 
                    className="form-select" 
                    value={formData.serviceType} 
                    onChange={handleChange}
                    style={{ padding: '10px', borderRadius: '8px' }}
                  >
                    <option value="Web Development">Web Development</option>
                    <option value="UI/UX Design">UI/UX Design</option>
                    <option value="Assignment Support">Assignment Support</option>
                    <option value="Report Writing">Report Writing</option>
                  </select>
                </div>

                {/* Payment Method */}
                <div className="mb-3">
                  <label className="form-label fw-bold text-danger">Payment Method</label>
                  <select 
                    name="paymentMethod" 
                    className="form-select border-danger" 
                    value={formData.paymentMethod} 
                    onChange={handleChange}
                    style={{ padding: '10px', borderRadius: '8px' }}
                  >
                    <option value="Cash">Cash / Direct Pay (After Work)</option>
                    <option value="Online">Online Payment (UPI / Card)</option>
                  </select>
                  <small className="text-muted">Note: Online payment is simulated for project demo.</small>
                </div>

                {/* Project Details */}
                <div className="mb-4">
                  <label className="form-label fw-bold">Project Details</label>
                  <textarea 
                    name="projectDetails" 
                    className="form-control" 
                    rows="4" 
                    value={formData.projectDetails} 
                    onChange={handleChange} 
                    required
                    style={{ padding: '10px', borderRadius: '8px' }}
                  ></textarea>
                </div>

                <div className="d-grid gap-2">
                  <button 
                    type="submit" 
                    className="btn btn-primary btn-lg fw-bold"
                    style={{ background: 'linear-gradient(135deg, #1e3c72 0%, #2a5298 100%)' }}
                  >
                    Send Request & Continue
                  </button>
                  <button 
                    type="button" 
                    onClick={() => {
                      setShowRegisterModal(false);
                      setMessage('');
                    }}
                    className="btn btn-outline-secondary"
                  >
                    Cancel
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {/* CSS Styles */}
      <style>{`
        .feature-card { transition: 0.3s; cursor: pointer; }
        .feature-card:hover { transform: translateY(-10px); box-shadow: 0 10px 20px rgba(0,0,0,0.1) !important; }
        .shadow-hover:hover { box-shadow: 0 10px 20px rgba(0,0,0,0.1) !important; transition: 0.3s; }
        .image-wrapper {
          background: rgba(255,255,255,0.1);
          backdrop-filter: blur(5px);
          position: relative;
          overflow: hidden;
        }
        .image-wrapper img {
          transition: opacity 0.5s ease-in-out;
        }
        @keyframes slideIn {
          from {
            transform: translateY(-50px);
            opacity: 0;
          }
          to {
            transform: translateY(0);
            opacity: 1;
          }
        }
      `}</style>
    </div>
  );
}

export default Home;
